export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "21:40。", background: Background.Chapter_6_Ch6_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "站務安全室。一張金屬桌。一把塑膠椅。牆上的監視螢幕顯示著車站各個角度的靜止畫面——月台、閘口、通道入口。轉角之後的畫面是灰色的。沒有訊號。", background: Background.Chapter_6_Ch6_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪坐在椅子上。她的手放在膝蓋上。血已經乾了，在她的指縫裡結成暗褐色的細線。桌上有一杯紙杯水。她沒有碰。", background: Background.Chapter_6_Ch6_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "對面坐著一個人。不是站務員了。是警察。先遣到場的。年輕。筆記本攤開，筆拿在手裡。", background: Background.Chapter_6_Ch6_Act7_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "名字。", background: Background.Chapter_6_Ch6_Act7_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "朝倉澪。", background: Background.Chapter_6_Ch6_Act7_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "年齡。", background: Background.Chapter_6_Ch6_Act7_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "十九。", background: Background.Chapter_6_Ch6_Act7_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "職業。", background: Background.Chapter_6_Ch6_Act7_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "大學生。在網路調查媒體兼職。", background: Background.Chapter_6_Ch6_Act7_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "為什麼在限制區？", background: Background.Chapter_6_Ch6_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看著他。他看著她。筆停在本子上，等她開口。", background: Background.Chapter_6_Ch6_Act7_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯我不能說「我上一輪看見他死在第七車裡」。我不能說「我記得循環」。我不能說「我知道他今晚會在這裡被殺」。", background: Background.Chapter_6_Ch6_Act7_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯我只能說一個說得通的故事。", background: Background.Chapter_6_Ch6_Act7_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "我收到一封匿名訊息。跟我弟弟失蹤有關。訊息叫我把弟弟留下的某件東西帶上，去搭第七車。我到了車站之後，看到有人把一個男人帶向施工通道。那個人穿維修服。戴口罩和帽子。我覺得不對。我跟了上去。", background: Background.Chapter_6_Ch6_Act7_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "妳怎麼知道那個男人會在這裡？", background: Background.Chapter_6_Ch6_Act7_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "我不知道。我原本是去搭第七車的。是看到他們往通道走才跟過去的。", background: Background.Chapter_6_Ch6_Act7_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "妳認識傷者嗎？", background: Background.Chapter_6_Ch6_Act7_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "不認識。", background: Background.Chapter_6_Ch6_Act7_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這是謊話。但她不能說「我認識他——因為上一輪他死在我面前，把銀色外殼塞給我，對我說不要救東京」。她不能說。", background: Background.Chapter_6_Ch6_Act7_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "有沒有看清維修人員？", background: Background.Chapter_6_Ch6_Act7_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "沒有。帽子、口罩、護目鏡。看不到臉。也分不出性別。中等身材。穿寬大的維修外套。手裡有平板和工具箱。", background: Background.Chapter_6_Ch6_Act7_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "攻擊發生的時候妳看到了嗎？", background: Background.Chapter_6_Ch6_Act7_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "沒有直接看到。我追到轉角的時候，千田已經靠在牆上了。維修人員在往側門退。我聽到一聲鈍響——像人撞上金屬欄杆。然後那個人刷卡從側門出去了。", background: Background.Chapter_6_Ch6_Act7_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "妳說的三件事——", background: Background.Chapter_6_Ch6_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他低頭看筆記。", background: Background.Chapter_6_Ch6_Act7_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "千田是在通道受傷。攻擊者穿維修服。攻擊者從側門逃走。對嗎？", background: Background.Chapter_6_Ch6_Act7_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "對。", background: Background.Chapter_6_Ch6_Act7_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "匿名訊息。能看一下嗎？", background: Background.Chapter_6_Ch6_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她掏出手機。螢幕亮起來。她點開訊息。遞過去。", background: Background.Chapter_6_Ch6_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "警察看了一眼。", background: Background.Chapter_6_Ch6_Act7_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "「帶上悠真留下的那件東西。」", background: Background.Chapter_6_Ch6_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他抬頭。", background: Background.Chapter_6_Ch6_Act7_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "那件東西是什麼？", background: Background.Chapter_6_Ch6_Act7_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯小鏡子。悠真書桌上的那面小鏡子。背面有受試者編號。我帶在身上。現在。就在我的口袋裡。", background: Background.Chapter_6_Ch6_Act7_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯不能拿出來。", background: Background.Chapter_6_Ch6_Act7_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯一旦拿出來，它就會變成證物。被登記。被拍照。被放進證物袋。然後悠真的最後一條線索就會消失在流程裡。和銀色外殼一樣。被送進去。不代表安全。", background: Background.Chapter_6_Ch6_Act7_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "我不確定。訊息沒有明說是什麼。我弟弟失蹤前留了一些東西。我還在查。", background: Background.Chapter_6_Ch6_Act7_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "警察看了她一會兒。然後低頭繼續寫。", background: Background.Chapter_6_Ch6_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有追問。不是因為他相信了。是因為現在的焦點不在這裡。焦點在傷者。在維修權限。在側門。在攻擊者怎麼逃的。", background: Background.Chapter_6_Ch6_Act7_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯問題被放到後面了。暫時。只是暫時。", background: Background.Chapter_6_Ch6_Act7_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "站務那邊回報，中央流沒有清楚拍到轉角。側門權限紀錄要走維修管理系統調取，站務端看不到。施工區不屬於乘客一般監控範圍。", background: Background.Chapter_6_Ch6_Act7_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "我親眼看見的。千田在通道裡受傷。不是在車廂裡。攻擊者穿維修服。從側門——", background: Background.Chapter_6_Ch6_Act7_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "我知道。我會記錄妳的陳述。但現場影像不完整，側門資料還沒調出來。目前能確認的是——", background: Background.Chapter_6_Ch6_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他翻了翻筆記。", background: Background.Chapter_6_Ch6_Act7_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "入口鏡頭拍到妳在21:04進入通道。傷者在妳之前進入。妳觸發了緊急通報。妳沒有持有凶器。妳在進行止血壓迫。", background: Background.Chapter_6_Ch6_Act7_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "暫時沒有把妳列為主要嫌疑。但妳非法進入了限制區。後續要配合調查。", background: Background.Chapter_6_Ch6_Act7_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "我知道。", background: Background.Chapter_6_Ch6_Act7_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "留下聯絡方式。明天可能會再請妳來做正式筆錄。", background: Background.Chapter_6_Ch6_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她報了電話號碼。他寫下來。合上筆記本。", background: Background.Chapter_6_Ch6_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她站起來。椅子在地板上刮了一聲。", background: Background.Chapter_6_Ch6_Act7_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯第一輪。我被車廂裡的死亡畫面困住。系統把我的影像整理成「持尖銳物者」。我拿著外殼。滿手血。沒有解釋的餘地。", background: Background.Chapter_6_Ch6_Act7_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯第二輪。我避開了那張畫面。第七車裡沒有屍體。我不持外殼。我不是主要嫌疑。", background: Background.Chapter_6_Ch6_Act7_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯但我親眼看見的東西——千田在通道受傷、攻擊者穿維修服、側門綠光——官方拿到的版本仍然是不完整的。中央流拍不到轉角。側門權限要更高層級才能調。施工區不在一般監控裡。", background: Background.Chapter_6_Ch6_Act7_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯我看到的。我說了。但真相進入系統之後，先變成了另一種格式。一個不完整的格式。一個等補完的格式。", background: Background.Chapter_6_Ch6_Act7_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯而補完的權力不在我手上。", background: Background.Chapter_6_Ch6_Act7_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她走到門口。警察沒有叫住她。", background: Background.Chapter_6_Ch6_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她推開門。站務走廊的冷白燈光照在她臉上。她的手還是髒的。她的袖口還是濕的。她的口袋裡有一面小鏡子，她沒有拿出來。", background: Background.Chapter_6_Ch6_Act7_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯我隱瞞了。我知道這是隱瞞。但我知道一旦交出去，悠真的最後線索就會被流程吞掉。", background: Background.Chapter_6_Ch6_Act7_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯和銀色外殼一樣。和千田一樣。被送進去。不代表安全。", background: Background.Chapter_6_Ch6_Act7_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她走出了安全室。走廊很長。盡頭是站務出口的方向。", background: Background.Chapter_6_Ch6_Act7_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯我改變了死亡現場。但真相進入系統的方式沒有改變。它還是會先被整理。先被壓縮。先變成別人能處理的格式。然後才輪到我說的話。", background: Background.Chapter_6_Ch6_Act7_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯第一輪我被畫面困住。第二輪我避開了畫面。卻發現——", background: Background.Chapter_6_Ch6_Act7_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯只要真相進入系統，就一定會先變成另一種格式。", background: Background.Chapter_6_Ch6_Act7_S0, portrait: Portrait.AsakuraMio_Determined },
];
